import pandas as pd

data = {
    "id": [1, 2, 2, 3, 4, 4, 7],
    "old_name": ["Karan", "Deepak", "Deepak", "Rahul", "Sachin", "Sachin", "Vikas"],
    "Column": [10, 20, 20, 30, 40, 40, 70]
}
df = pd.DataFrame(data)

def clean_names(df):
    return df.rename(columns={"old_name": "new_name"})

def drop_duplicates(df):
    return df.drop_duplicates(subset=["id"])

def convert_types(df):
    return df.astype({"Column": "int"})

# Chain transformations with .pipe()
processed_df = (
    df.pipe(clean_names)
      .pipe(drop_duplicates)
      .pipe(convert_types)
)

print(processed_df)

