# Minimal schema validation before preprocessing
import pandas as pd

REQUIRED_COLUMNS = {"age", "annual_income", "credit_score", "loan_amount",
                    "employment_status", "loan_purpose"}
EXPECTED_DTYPES = {
    "age": "int64",
    "credit_score": "int64",
}

def validate_schema(df: pd.DataFrame) -> None:
    missing = REQUIRED_COLUMNS - set(df.columns)
    if missing:
        raise ValueError(f"Missing required columns: {missing}")
    for col, dtype in EXPECTED_DTYPES.items():
        if str(df[col].dtype) != dtype:
            raise TypeError(f"Column {col} expected {dtype}, got {df[col].dtype}")
    # Value range checks
    if not df["age"].between(0, 130).all():
        raise ValueError("Age values out of valid range [0, 130]")
    if not df["credit_score"].between(300, 850).all():
        raise ValueError("Credit score out of valid range [300, 850]")
    missing_rate = df.isnull().mean()
    high_missing = missing_rate[missing_rate > 0.5]
    if not high_missing.empty:
        raise RuntimeError(f"Suspiciously high missing rate: {high_missing.to_dict()}")
